glass main() -> Int {
  drink x: Int = 42;
  return x;
}

glass main() -> Int {
  drink x: Int = 1;
  drink x: Int = 2;
  return 0;
}

glass main() -> Int {
  pour(undefined_var);
  return 0;
}

glass main() -> Int {
  drink x: Int = 1;
  x = 2;
  return 0;
}

glass get_name() -> Int {
  return "alice";
}
glass main() -> Int {
  return 0;
}

glass main() -> Int {
  thirsty (42) {
    pour("yes");
  }
  return 0;
}

glass main() -> Int {
  refill "three" times {
    pour("x");
  }
  return 0;
}

glass add(a: Int, b: Int) -> Int { return a + b; }
glass main() -> Int {
  pour(add(1));
  return 0;
}

glass main() -> Int {
  drink x: Int = 5;
  x();
  return 0;
}

glass get_float() -> Float {
  return 1;
}
glass main() -> Int {
  pour(get_float());
  return 0;
}

glass main() -> Int {
  drink mut x: Int = 1;
  x = 99;
  pour(x);
  return 0;
}

glass main() -> Int {
  drink x: Int = 0;
  drip x;
  return 0;
}

glass main() -> Int {
  drink x: Any = "anything";
  drink y: Any = 42;
  pour(x);
  pour(y);
  return 0;
}

glass main() -> Int {
  drink xs: Reservoir[Int] = [1, 2, 3];
  pour(size(xs));
  return 0;
}

glass main() -> Int {
  drink xs: Reservoir[Int] = [1, 2, 3, 4, 5];
  drink evens: Reservoir[Int] = strain(xs, glass(x: Int) -> Bool { return x % 2 == 0; });
  pour(size(evens));
  return 0;
}

glass main() -> Int {
  drink xs: Reservoir[Int] = [1, 2, 3];
  drink doubled: Reservoir[Int] = transmute(xs, glass(x: Int) -> Int { return x * 2; });
  pour(get(doubled, 0));
  return 0;
}

glass main() -> Int {
  drink xs: Reservoir[Int] = [1, 2, 3, 4];
  drink total: Int = distill(xs, 0, glass(acc: Int, x: Int) -> Int { return acc + x; });
  pour(total);
  return 0;
}

glass main() -> Int {
  pour(abs(-7));
  return 0;
}

glass main() -> Int {
  pour(min(3, 7));
  return 0;
}

glass main() -> Int {
  pour(max(3, 7));
  return 0;
}

glass main() -> Int {
  drink parts: Reservoir[String] = split("a,b,c", ",");
  pour(size(parts));
  return 0;
}

glass main() -> Int {
  pour(contains("hello", "xyz"));
  return 0;
}

glass main() -> Int {
  drink mut xs: Reservoir[Int] = [10, 20, 30];
  drink val: Any = pop(xs);
  pour(val);
  pour(size(xs));
  return 0;
}

glass main() -> Int {
  drink mut xs: Reservoir[Int] = [1, 2];
  flood(xs, [3, 4]);
  pour(size(xs));
  return 0;
}

glass classify(n: Int) -> String {
  thirsty (n > 0) {
    return "positive";
  } hydrated {
    return "non-positive";
  }
}
glass main() -> Int {
  pour(classify(5));
  pour(classify(-1));
  return 0;
}
